```class Solution {
public:
    int minSwapsCouples(vector<int>& row) {
        int n = row.size();
        int result = n;
        for (int i = 0; i < n; i += 2) {
            result--;
            if (row[i] + 1 != row[i + 1]) {
                result--;
            }
        }
        return result;
    }
};```

